css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { min-height: 100vh; display: flex; align-items: center; justify-content: center; background: radial-gradient(ellipse at top, #2a1505 0%, #070b18 60%); padding: 24px; }
.card { width: 100%; max-width: 420px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 24px; padding: 40px 36px; backdrop-filter: blur(20px); box-shadow: 0 30px 60px rgba(0,0,0,0.4); text-align: center; }
.icon-circle { width: 60px; height: 60px; border-radius: 50%; background: linear-gradient(135deg, #f97316, #ea580c); display: flex; align-items: center; justify-content: center; margin: 0 auto 22px; color: white; box-shadow: 0 10px 30px rgba(249,115,22,0.35); }
h1 { color: white; font-size: 26px; font-weight: 700; margin-bottom: 10px; }
.sub { color: rgba(255,255,255,0.55); font-size: 14px; line-height: 1.6; margin-bottom: 28px; }
form { text-align: left; }
label { display: block; color: rgba(255,255,255,0.7); font-size: 13px; font-weight: 600; margin-bottom: 8px; }
input { width: 100%; padding: 14px 16px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.1); background: rgba(255,255,255,0.05); color: white; font-size: 15px; margin-bottom: 22px; outline: none; transition: border 0.2s; }
input:focus { border-color: #f97316; }
input::placeholder { color: rgba(255,255,255,0.3); }
.btn-primary { width: 100%; padding: 15px; border: none; border-radius: 12px; background: linear-gradient(135deg, #f97316, #ea580c); color: white; font-size: 15px; font-weight: 700; cursor: pointer; box-shadow: 0 12px 30px rgba(249,115,22,0.3); transition: transform 0.15s; }
.btn-primary:active { transform: scale(0.98); }
.btn-secondary { width: 100%; padding: 14px; border: 1px solid rgba(255,255,255,0.15); border-radius: 12px; background: transparent; color: white; font-size: 14px; font-weight: 600; cursor: pointer; margin-top: 22px; }
.back-link { display: inline-block; margin-top: 24px; color: rgba(255,255,255,0.45); font-size: 13px; text-decoration: none; }
.back-link:hover { color: #f97316; }
.success { animation: fadeUp 0.4s ease; }
.success.hidden { display: none; }
.success-icon { width: 60px; height: 60px; border-radius: 50%; background: linear-gradient(135deg, #22c55e, #16a34a); display: flex; align-items: center; justify-content: center; margin: 0 auto 20px; color: white; box-shadow: 0 10px 30px rgba(34,197,94,0.35); }
.success h2 { color: white; font-size: 22px; font-weight: 700; margin-bottom: 10px; }
#emailDisplay { color: #f97316; font-weight: 600; }
@keyframes fadeUp { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }

js:
const form = document.getElementById('form');
const success = document.getElementById('success');
const emailDisplay = document.getElementById('emailDisplay');

form.addEventListener('submit', function(e) {
  e.preventDefault();
  const email = document.getElementById('email').value;
  emailDisplay.textContent = email;
  form.style.display = 'none';
  success.classList.remove('hidden');
});

function reset() {
  form.reset();
  form.style.display = 'block';
  success.classList.add('hidden');
}
